const body = $input.first().json.body;
const headers = $input.first().json.headers || {};

// Stripe signature verification placeholder
// In production, verify using the stripe-signature header and your webhook signing secret.
// n8n Code nodes don't have native crypto, so for now we rely on the webhook URL being secret.
// TODO: Add full HMAC-SHA256 verification when deploying to production.

const eventType = body.type || '';
const eventData = body.data && body.data.object ? body.data.object : {};

// Extract common fields
const email = eventData.customer_email || eventData.customer_details?.email || '';
const metadata = eventData.metadata || {};
const projectType = metadata.projectType || metadata.product_type || 'cosmetic';
const subscriptionId = eventData.subscription || eventData.id || '';
const customerId = eventData.customer || '';

return [{ json: {
  eventType,
  email: email.toLowerCase().trim(),
  projectType,
  subscriptionId,
  customerId,
  plan: 'basic',
  rawEvent: body
} }];

const regResponse = $input.first().json;
let result;

// Registration response is a JSON string in the 'result' field
try {
  if (typeof regResponse.result === 'string') {
    result = JSON.parse(regResponse.result);
  } else {
    result = regResponse;
  }
} catch (e) {
  result = regResponse;
}

if (!result.success) {
  return [{ json: { action: 'registration_failed', error: result.error || 'Unknown error', email: $('Parse Stripe Event').first().json.email } }];
}

return [{ json: {
  action: 'user_registered',
  email: result.email,
  authToken: result.authToken,
  spreadsheetId: result.spreadsheetId,
  projectType: result.projectType,
  plan: result.plan
} }];

const data = $input.first().json;
const projectType = data.projectType || 'cosmetic';
const baseUrl = 'https://princeadarkwah.app.n8n.cloud';

let chatUrl, productName;
if (projectType === 'project') {
  chatUrl = baseUrl + '/webhook/project-assistant-chat';
  productName = 'Project Management AI Assistant';
} else {
  chatUrl = baseUrl + '/webhook/cosmetic-chat';
  productName = 'Cosmetic Formulation AI Assistant';
}

// Build welcome email HTML
const emailHtml = `
<h2>Welcome to ${productName}!</h2>
<p>Hi ${data.email},</p>
<p>Your subscription is now active. Here's how to get started:</p>
<ol>
  <li><strong>Open your AI assistant:</strong> <a href="${chatUrl}">${chatUrl}</a></li>
  <li><strong>Your auth token:</strong> <code>${data.authToken}</code></li>
  <li>The token is already saved in the chat interface — just open the link and start chatting!</li>
</ol>
<p><strong>Your plan includes:</strong></p>
<ul>
  <li>100 conversations per month</li>
  <li>Your own private data spreadsheet</li>
  <li>Usage resets on the 1st of each month</li>
</ul>
<p>Need help? Reply to this email.</p>
<p>— The FormulateAI Team</p>
`;

return [{ json: {
  to: data.email,
  subject: `Your ${productName} is Ready!`,
  html: emailHtml,
  authToken: data.authToken,
  chatUrl
} }];

const email = $('Parse Stripe Event').first().json.email;
const users = $input.all();

if (!users || users.length === 0 || !users[0].json.AuthToken) {
  return [{ json: { found: false, error: 'No users in registry' } }];
}

// Find user by email
const userIdx = users.findIndex(u => 
  (u.json.Email || '').toLowerCase().trim() === email
);

if (userIdx === -1) {
  return [{ json: { found: false, error: 'User not found: ' + email } }];
}

const rowNumber = userIdx + 2; // +2 for header row + 0-index
return [{ json: {
  found: true,
  email,
  rowNumber,
  action: 'deactivate'
} }];
